config.script:
// avisos-diretivas-ui / orcamento_aprovado_aviso (#1168 B6) — cenário de validação
// da primitiva de diretivas de UI (agente -> tela). Ao aprovar um orçamento, empurra
// um MODAL persistente pra equipe (alvo por role) com um botão LINK 'ver o orçamento'.
// Config-driven: `config.alvo_role` (quem vê) e `config.base_path` (rota da Central).
//
// Injetados pelo runtime: event ({event_type, subject, payload_safe}), config, call(), log().
// call('emitir_ui', <corpo do POST /diretivas>) — capability curada; RBAC do SA é a jaula.

var subject = event.subject || {};
var safe = event.payload_safe || {};

var orcId = subject.orcamento_id || subject.id;
if (!orcId) { log('aviso: evento sem orcamento_id'); return { skip: 'sem_orcamento_id' }; }
orcId = String(orcId);

var numero = safe.numero || orcId;
var alvoRole = config.alvo_role || 'recepcionista';
var basePath = config.base_path || '/vendas/orcamentos/';

var r = call('emitir_ui', {
  type: 'diretiva_ui',
  kind: 'modal',
  titulo: 'Orçamento aprovado',
  corpo: 'O orçamento **' + numero + '** foi aprovado. Você pode dar sequência.',
  botoes: [
    { label: 'Ver o orçamento', estilo: 'primary', acao: { tipo: 'link', href: basePath + orcId } }
  ],
  alvo: { role: alvoRole },
  persistencia: 'persistente'
});

if (r && r.ok === false) { log('aviso: emitir_ui falhou HTTP ' + r.status_code); return { erro: 'emitir_ui', status: r.status_code }; }
log('aviso: diretiva de UI emitida p/ role=' + alvoRole + ' (orcamento ' + numero + ')');
return { emitido: true, orcamento_id: orcId, alvo_role: alvoRole };
